firmware_template.source:
#include "gps_neo6m.h"
#include <TinyGPSPlus.h>
#include <HardwareSerial.h>
static TinyGPSPlus gps;
static HardwareSerial gpsSerial(1);
static double _lat=0,_lng=0;static float _alt=0,_spd=0;static int _sat=0;
void gps_setup(){gpsSerial.begin(9600,SERIAL_8N1,16,17);Serial.println("[gps] OK");}
void gps_loop(){
  while(gpsSerial.available())gps.encode(gpsSerial.read());
  if(gps.location.isUpdated()){_lat=gps.location.lat();_lng=gps.location.lng();}
  if(gps.altitude.isUpdated())_alt=gps.altitude.meters();
  if(gps.speed.isUpdated())_spd=gps.speed.kmph();
  if(gps.satellites.isUpdated())_sat=gps.satellites.value();
}
double gps_get_lat(){return _lat;}
double gps_get_lng(){return _lng;}
float gps_get_altitude(){return _alt;}
float gps_get_speed(){return _spd;}
int gps_get_satellites(){return _sat;}
